INSERT INTO checklist_templates (id, nome, descricao, ativo, criado_por) VALUES (
  '00000000-0000-0000-0001-000000000001',
  'Checklist Frota Padrão — REG.047',
  'Template inicial baseado no CHECKLIST FROTA 2022 / REG.047 — Troca de Motorista e Saída. Mantém legenda X, N, A e N/A e prepara auditorias quinzenais.',
