  exige_foto = EXCLUDED.exige_foto,
  exige_obs_se_nao_ok = EXCLUDED.exige_obs_se_nao_ok,
  item_critico = EXCLUDED.item_critico,
  aplica_cavalo = EXCLUDED.aplica_cavalo,
  aplica_carreta = EXCLUDED.aplica_carreta,
  aplica_bau = EXCLUDED.aplica_bau,
  aplica_truck = EXCLUDED.aplica_truck,
  aplica_carro_passeio = EXCLUDED.aplica_carro_passeio,
  aplica_guindaste = EXCLUDED.aplica_guindaste,
  ordem = EXCLUDED.ordem,
  ativo = EXCLUDED.ativo;


-- Regra padrão: itens não conformes devem receber foto na implementação do formulário,
-- mesmo que exige_foto seja FALSE no checklist base.
INSERT INTO checklist_item_rules (item_id, regra, valor)
SELECT id, 'exige_foto_se_nao_ok', 'true'
FROM checklist_items
WHERE categoria_id IN (SELECT id FROM checklist_categorias WHERE template_version_id = '00000000-0000-0000-0002-000000000001')
ON CONFLICT DO NOTHING;
